import 'dart:convert';

class UserModel {
  final String id;
  final String email;
  final String displayName;
  final String? avatarUrl;
  final Map<String, dynamic>? metadata;

  UserModel({
    required this.id,
    required this.email,
    required this.displayName,
    this.avatarUrl,
    this.metadata,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'email': email,
        'displayName': displayName,
        'avatarUrl': avatarUrl,
        'metadata': metadata,
      };

  factory UserModel.fromJson(Map<String, dynamic> json) => UserModel(
        id: json['id'] as String,
        email: json['email'] as String,
        displayName: json['displayName'] as String,
        avatarUrl: json['avatarUrl'] as String?,
        metadata: json['metadata'] as Map<String, dynamic>?,
      );

  String toJsonString() => jsonEncode(toJson());

  factory UserModel.fromJsonString(String jsonString) =>
      UserModel.fromJson(jsonDecode(jsonString) as Map<String, dynamic>);

  @override
  String toString() =>
      'UserModel(id: $id, email: $email, displayName: $displayName)';

  UserModel copyWith({
    String? id,
    String? email,
    String? displayName,
    String? avatarUrl,
    Map<String, dynamic>? metadata,
  }) {
    return UserModel(
      id: id ?? this.id,
      email: email ?? this.email,
      displayName: displayName ?? this.displayName,
      avatarUrl: avatarUrl ?? this.avatarUrl,
      metadata: metadata ?? this.metadata,
    );
  }
}

// lib/models/auth_tokens.dart
class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;

  AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
  });

  bool get isExpired => DateTime.now().isAfter(expiresAt);

  bool get isAboutToExpire =>
      DateTime.now().isAfter(expiresAt.subtract(const Duration(minutes: 5)));

  Map<String, dynamic> toJson() => {
        'accessToken': accessToken,
        'refreshToken': refreshToken,
        'expiresAt': expiresAt.toIso8601String(),
      };

  factory AuthTokens.fromJson(Map<String, dynamic> json) => AuthTokens(
        accessToken: json['accessToken'] as String,
        refreshToken: json['refreshToken'] as String,
        expiresAt: DateTime.parse(json['expiresAt'] as String),
      );
}

// lib/services/secure_storage_service.dart
import 'dart:convert';
import 'package:shared_preferences/shared_preferences.dart';

class SecureStorageService {
  static const String _accessTokenKey = 'auth_access_token';
  static const String _refreshTokenKey = 'auth_refresh_token';
  static const String _tokenExpiryKey = 'auth_token_expiry';
  static const String _userDataKey = 'auth_user_data';
  static const String _isLoggedInKey = 'auth_is_logged_in';
  static const String _lastLoginKey = 'auth_last_login';
  static const String _rememberMeKey = 'auth_remember_me';

  SharedPreferences? _prefs;

  Future<SharedPreferences> get prefs async {
    _prefs ??= await SharedPreferences.getInstance();
    return _prefs!;
  }

  // Token operations
  Future<void> saveTokens({
    required String accessToken,
    required String refreshToken,
    required DateTime expiresAt,
  }) async {
    final p = await prefs;
    await Future.wait([
      p.setString(_accessTokenKey, accessToken),
      p.setString(_refreshTokenKey, refreshToken),
      p.setString(_tokenExpiryKey, expiresAt.toIso8601String()),
    ]);
  }

  Future<String?> getAccessToken() async {
    final p = await prefs;
    return p.getString(_accessTokenKey);
  }

  Future<String?> getRefreshToken() async {
    final p = await prefs;
    return p.getString(_refreshTokenKey);
  }

  Future<DateTime?> getTokenExpiry() async {
    final p = await prefs;
    final expiryStr = p.getString(_tokenExpiryKey);
    if (expiryStr == null) return null;
    return DateTime.tryParse(expiryStr);
  }

  Future<bool> isTokenExpired() async {
    final expiry = await getTokenExpiry();
    if (expiry == null) return true;
    return DateTime.now().isAfter(expiry);
  }

  // User data operations
  Future<void> saveUserData(Map<String, dynamic> userData) async {
    final p = await prefs;
    await p.setString(_userDataKey, jsonEncode(userData));
  }

  Future<Map<String, dynamic>?> getUserData() async {
    final p = await prefs;
    final dataStr = p.getString(_userDataKey);
    if (dataStr == null) return null;
    try {
      return jsonDecode(dataStr) as Map<String, dynamic>;
    } catch (_) {
      return null;
    }
  }

  // Session state
  Future<void> setLoggedIn(bool value) async {
    final p = await prefs;
    await p.setBool(_isLoggedInKey, value);
    if (value) {
      await p.setString(_lastLoginKey, DateTime.now().toIso8601String());
    }
  }

  Future<bool> isLoggedIn() async {
    final p = await prefs;
    return p.getBool(_isLoggedInKey) ?? false;
  }

  Future<DateTime?> getLastLogin() async {
    final p = await prefs;
    final str = p.getString(_lastLoginKey);
    if (str == null) return null;
    return DateTime.tryParse(str);
  }

  Future<void> setRememberMe(bool value) async {
    final p = await prefs;
    await p.setBool(_rememberMeKey, value);
  }

  Future<bool> getRememberMe() async {
    final p = await prefs;
    return p.getBool(_rememberMeKey) ?? false;
  }

  // Clear all auth data
  Future<void> clearAll() async {
    final p = await prefs;
    await Future.wait([
      p.remove(_accessTokenKey),
      p.remove(_refreshTokenKey),
      p.remove(_tokenExpiryKey),
      p.remove(_userDataKey),
      p.remove(_isLoggedInKey),
      p.remove(_lastLoginKey),
    ]);
  }
}

