import 'dart:async';
import 'package:flutter/foundation.dart';

enum AuthState {
  initial,
  loading,
  authenticated,
  unauthenticated,
  error,
}

class AuthManager extends ChangeNotifier {
  final SecureStorageService _storage;
  final AuthApiService _api;

  AuthState _state = AuthState.initial;
  UserModel? _currentUser;
  AuthTokens? _tokens;
  String? _errorMessage;
  Timer? _tokenRefreshTimer;

  AuthManager({
    SecureStorageService? storage,
    AuthApiService? api,
  })  : _storage = storage ?? SecureStorageService(),
        _api = api ?? AuthApiService();

  // Getters
  AuthState get state => _state;
  UserModel? get currentUser => _currentUser;
  AuthTokens? get tokens => _tokens;
  String? get errorMessage => _errorMessage;
  bool get isAuthenticated => _state == AuthState.authenticated;
  bool get isLoading => _state == AuthState.loading;

  // Initialize - check for existing session
  Future<void> initialize() async {
    _setState(AuthState.loading);

    try {
      final isLoggedIn = await _storage.isLoggedIn();
      if (!isLoggedIn) {
        _setState(AuthState.unauthenticated);
        return;
      }

      final accessToken = await _storage.getAccessToken();
      final refreshToken = await _storage.getRefreshToken();
      final expiry = await _storage.getTokenExpiry();
      final userData = await _storage.getUserData();

      if (accessToken == null ||
          refreshToken == null ||
          expiry == null ||
          userData == null) {
        await _storage.clearAll();
        _setState(AuthState.unauthenticated);
        return;
      }

      _tokens = AuthTokens(
        accessToken: accessToken,
        refreshToken: refreshToken,
        expiresAt: expiry,
      );

      // If token is expired, try to refresh
      if (_tokens!.isExpired) {
        final refreshed = await _tryRefreshTokens();
        if (!refreshed) {
          await _clearSession();
          _setState(AuthState.unauthenticated);
          return;
        }
      }

      _currentUser = UserModel.fromJson(userData);
      _scheduleTokenRefresh();
      _setState(AuthState.authenticated);
    } catch (e) {
      debugPrint('Auth initialization error: $e');
      await _clearSession();
      _setState(AuthState.unauthenticated);
    }
  }

  // Login
  Future<bool> login({
    required String email,
    required String password,
    bool rememberMe = true,
  }) async {
    _setState(AuthState.loading);
    _errorMessage = null;

    try {
      final response = await _api.login(email, password);

      final user =
          UserModel.fromJson(response['user'] as Map<String, dynamic>);
      final tokens = AuthTokens(
        accessToken: response['accessToken'] as String,
        refreshToken: response['refreshToken'] as String,
        expiresAt: DateTime.parse(response['expiresAt'] as String),
      );

      await _saveSession(user: user, tokens: tokens, rememberMe: rememberMe);

      _currentUser = user;
      _tokens = tokens;
      _scheduleTokenRefresh();
      _setState(AuthState.authenticated);
      return true;
    } on AuthException catch (e) {
      _errorMessage = e.message;
      _setState(AuthState.error);
      return false;
    } catch (e) {
      _errorMessage = 'An unexpected error occurred. Please try again.';
      _setState(AuthState.error);
      return false;
    }
  }

  // Register
  Future<bool> register({
    required String email,
    required String password,
    required String displayName,
  }) async {
    _setState(AuthState.loading);
    _errorMessage = null;

    try {
      final response = await _api.register(email, password, displayName);

      final user =
          UserModel.fromJson(response['user'] as Map<String, dynamic>);
      final tokens = AuthTokens(
        accessToken: response['accessToken'] as String,
        refreshToken: response['refreshToken'] as String,
        expiresAt: DateTime.parse(response['expiresAt'] as String),
      );

      await _saveSession(user: user, tokens: tokens, rememberMe: true);

      _currentUser = user;
      _tokens = tokens;
      _scheduleTokenRefresh();
      _setState(AuthState.authenticated);
      return true;
    } on AuthException catch (e) {
      _errorMessage = e.message;
      _setState(AuthState.error);
      return false;
    } catch (e) {
      _errorMessage = 'An unexpected error occurred. Please try again.';
      _setState(AuthState.error);
      return false;
    }
  }